with.command:
${ "set -eu
TARGET=/sandbox/repo
rm -rf "$TARGET"
git clone --depth 50 --branch " + (.trigger.branch // "main") + " " + .trigger.repoUrl + " "$TARGET"
cd "$TARGET"
echo CLONED_AT=$(git rev-parse HEAD)
echo BRANCH=$(git rev-parse --abbrev-ref HEAD)
ls -la "$TARGET" | head -40" }

